import './CalendarMobileMonths.scss';

import type { CalendatRangeStatusOfDays } from ':components/DatePicker/Calendar/Calendar.types';
import { classNames } from ':helpers/classnames';
import { getBEMClasses } from ':helpers/get-bem';
import type { FC } from 'react';
import React, { useEffect, useRef } from 'react';

import { MONTHS_NAMES, WEEKDAYS } from '../../constants';
import { getWeeksOfMonths, hasDateLimit, isRangeMode, isSameDates } from '../../utils';
import type { CalendarMobileMonthsProps, Day } from './CalendarMobileMonths.types';

const [, calendarModifier, calendarBlock] = getBEMClasses('dsb_calendar-mobile');
const [monthsClassName, monthsModifier] = calendarBlock('months');

export const CalendarMobileMonths: FC<CalendarMobileMonthsProps> = ({
	minDate,
	maxDate,
	disabledStartDate,
	disabledEndDate,
	viewDate,
	selectedDate,
	onSelectDay,
	multiselect,
	readonly,
}) => {
	const today = new Date();
	const viewYear = viewDate.getFullYear();
	const viewMonth = viewDate.getMonth();
	// Если maxDate не задан, показываем +10 лет вперед, чтобы можно было скроллить
	const defaultMaxYear = viewYear + 10;
	const calculatedMaxYear = maxDate ? maxDate.getFullYear() : defaultMaxYear;
	const monthsWeeks = getWeeksOfMonths(viewYear, minDate?.getFullYear(), calculatedMaxYear);
	const monthsRef = useRef<HTMLTableElement>(null);

	useEffect(() => {
		/**
		 * Скролл до активного месяца, поиск в рамках контейнера месяцев а не глобального document,
		 * работает при MicroFrontend и shadowDOM
		 * */
		const id = `${viewYear}-${viewMonth}`;
		const monthsObj = monthsRef?.current;
		// В тестовой среде (jsdom) scrollIntoView может отсутствовать, поэтому вызываем безопасно
		const targetEl = monthsObj?.getElementsByClassName(id)[0] as HTMLElement | undefined;
		try {
			(targetEl as any)?.scrollIntoView?.();
		} catch {
			/* no-op: в окружениях без scrollIntoView просто пропускаем */
		}
	}, [viewYear, viewMonth]);

	const handleSelectDay = (day: Day, month: number, year: number): void => {
		if (day) {
			onSelectDay(day, month, year);
		}
	};

	const isCurrentDay = (day: Day, month: number, year: number): boolean => {
		if (day) {
			const checkedDate = new Date(year, month, day);
			return isSameDates(checkedDate, today);
		}

		return false;
	};

	const isSelectedDay = (day: Day, month: number, year: number): boolean => {
		if (day) {
			const checkedDate = new Date(year, month, day);

			/**
			 * Расчёт стиля для контролла "День"
			 * условие, что параметр "стартовая/конечная дата заблокирована для выбора" - disabledStartValue/disabledFinishValue может быть true
			 */
			const getRangeModeSelectedDate = (): boolean => {
				if (disabledStartDate && disabledEndDate) {
					return false;
				}

				if (disabledStartDate) {
					return Array.isArray(selectedDate) && selectedDate.indexOf(checkedDate) === 1;
				}

				if (disabledEndDate) {
					return Array.isArray(selectedDate) && selectedDate.indexOf(checkedDate) === 0;
				}

				return Array.isArray(selectedDate) && selectedDate?.some(date => date && isSameDates(date, checkedDate));
			};

			return isRangeMode(selectedDate)
				? getRangeModeSelectedDate()
				: selectedDate && isSameDates(selectedDate, checkedDate);
		}

		return false;
	};

	const isDisabledDay = (day: Day, month: number, year: number): boolean => {
		if (day) {
			// Используем UTC-полуночь для корректного сравнения с min/max без сдвигов по TZ
			const checkedDate = new Date(Date.UTC(year, month, day));
			return hasDateLimit(checkedDate, minDate, maxDate);
		}

		return false;
	};

	const getRangeStatusOfDay = (day: Day, month: number, year: number): Partial<CalendatRangeStatusOfDays> => {
		if (multiselect) {
			return {};
		}

		if (day && isRangeMode(selectedDate)) {
			const [startDay, endDay] = selectedDate;
			const isFilledRange = startDay && endDay;
			const checkedDate = new Date(year, month, day);

			/**
	   Даты без учёта времени, приравняв часы в 00:00:00:000
	   */
			const startDayMidnight = startDay && new Date(new Date(startDay).setHours(0, 0, 0, 0));
			const endDayMidnight = endDay && new Date(new Date(endDay).setHours(0, 0, 0, 0));

			/**
	   Расчёт стартовой даты
	   + условие, что параметр "стартовая дата заблокирована для выбора" - disabledStartValue может быть true
	   */
			const getStarting = (): boolean => {
				if (disabledStartDate) {
					return false;
				}

				return isFilledRange && isSameDates(startDay, checkedDate);
			};

			/**
	   Расчёт конечной даты
	   + условие, что параметр "конечная дата заблокирована для выбора" - disabledFinishValue может быть true
	   */
			const getEnding = (): boolean => {
				if (disabledEndDate) {
					return false;
				}

				return isFilledRange && isSameDates(endDay, checkedDate);
			};

			return {
				starting: getStarting(),
				ranging: startDayMidnight && startDayMidnight <= checkedDate && endDayMidnight && endDayMidnight >= checkedDate,
				ending: getEnding(),
			};
		}

		return {};
	};

	return (
		<div className={classNames(calendarModifier('panel'), { readonly })}>
			<table className={classNames(calendarModifier('dates'), calendarModifier('panel-header'))}>
				<thead className={calendarModifier('weekdays')}>
					<tr>
						{WEEKDAYS.map(weekday => (
							<th className={calendarModifier('weekday')} key={weekday}>
								{weekday}
							</th>
						))}
					</tr>
				</thead>
			</table>
			<div ref={monthsRef} className={monthsClassName}>
				{monthsWeeks.map(({ month, year, monthWeeks }) => (
					<div
						key={`${year}-${month}`}
						id={`${year}-${month}`}
						className={classNames(monthsModifier('month'), `${year}-${month}`)}
					>
						<span className={monthsModifier('month--title')}>{`${MONTHS_NAMES[month]} ${year}`}</span>
						<table className={calendarModifier('dates')}>
							<tbody className={calendarModifier('weeks')}>
								{monthWeeks.map((week, index) => (
									<tr key={`week-${index}`}>
										{week.map((day, index) => (
											<td
												className={classNames(calendarModifier('day-cell'), {
													...getRangeStatusOfDay(day, month, year),
												})}
												key={`day-${index}`}
											>
												<span
													className={classNames(calendarModifier('day'), {
														today: isCurrentDay(day, month, year),
														disabled: isDisabledDay(day, month, year),
														selected: isSelectedDay(day, month, year),
														readonly: !!readonly,
														[calendarModifier('day__empty')]: day === null,
													})}
													onClick={(): void => handleSelectDay(day, month, year)}
												>
													{day}
												</span>
											</td>
										))}
									</tr>
								))}
							</tbody>
						</table>
					</div>
				))}
			</div>
		</div>
	);
};
